<template>
  <div class="data-visualization-page page">
    <h1 class="page-title animate__animated animate__fadeInDown">Z世代认知图谱</h1>
    <p class="page-subtitle animate__animated animate__fadeIn animate__delay-1s">
      基于350+份问卷的真实数据
    </p>

    <!-- 认知度模块 -->
    <div class="data-section animate__animated animate__fadeInUp animate__delay-1s">
      <h2 class="section-title">
        <i class="el-icon-view"></i>
        认知度：听说过 ≠ 真了解
      </h2>

      <!-- 核心数据对比 -->
      <div class="stat-comparison">
        <div class="stat-item">
          <div class="stat-number" ref="heardOf">0</div>
          <div class="stat-label">听说过增城榄雕</div>
          <div class="stat-bar" :style="{ width: surveyData.awareness.heardOf + '%' }"></div>
        </div>
        <div class="stat-divider">VS</div>
        <div class="stat-item">
          <div class="stat-number" ref="knowMaterial">0</div>
          <div class="stat-label">能准确说出原料</div>
          <div class="stat-bar" :style="{ width: surveyData.awareness.knowMaterial + '%' }"></div>
        </div>
      </div>

      <!-- 认知渠道图表 -->
      <div class="chart-wrapper">
        <h3 class="chart-title">认知渠道分布</h3>
        <v-chart class="chart" :option="channelChartOption" autoresize />
        <div class="chart-source">
          <i class="el-icon-document"></i>
          数据来源：问卷星调查 · 有效样本 n=371 · 发放时间 2025.12—2026.01
        </div>
      </div>

      <!-- 词云展示 -->
      <div class="word-cloud-section">
        <h3 class="chart-title">Z世代眼中的榄雕关键词</h3>
        <div class="word-cloud">
          <div
            v-for="(word, index) in surveyData.awareness.keywords"
            :key="index"
            class="word-item"
            :style="getWordStyle(word.value)"
          >
            {{ word.text }}
          </div>
        </div>
        <div class="chart-source">
          <i class="el-icon-document"></i>
          数据来源：问卷星开放题整理 · 筛选条件：1995—2009年出生且常住广州增城
        </div>
      </div>
    </div>

    <!-- 兴趣度模块 -->
    <div class="data-section animate__animated animate__fadeInUp animate__delay-2s">
      <h2 class="section-title">
        <i class="el-icon-star-on"></i>
        兴趣度：愿意看 ≠ 愿意学
      </h2>

      <!-- 雷达图 -->
      <div class="chart-wrapper">
        <h3 class="chart-title">Z世代兴趣维度评分（5分制）</h3>
        <v-chart class="chart" :option="radarChartOption" autoresize />
        <div class="chart-source">
          <i class="el-icon-document"></i>
          数据来源：问卷星调查 · 李克特5分量表 · n=371
        </div>
      </div>

      <!-- 关键结论 -->
      <div class="conclusion-card">
        <div class="conclusion-item highlight">
          <span class="number">76.55%</span>
          <span class="text">愿意转发相关内容</span>
        </div>
        <div class="conclusion-divider">但是</div>
        <div class="conclusion-item">
          <span class="number">13.75%</span>
          <span class="text">愿意系统性学习</span>
        </div>
      </div>

      <div class="insight-box">
        <i class="el-icon-warning"></i>
        <p><strong>34.21%</strong> 的受访者认为榄雕与自己无关</p>
      </div>
    </div>

    <!-- 参与度模块 -->
    <div class="data-section animate__animated animate__fadeInUp animate__delay-3s">
      <h2 class="section-title">
        <i class="el-icon-data-line"></i>
        参与度：过去 vs 未来
      </h2>

      <!-- 对比柱状图 -->
      <div class="chart-wrapper">
        <h3 class="chart-title">过去一年参与经历 vs 未来参与意愿</h3>
        <v-chart class="chart" :option="participationChartOption" autoresize />
        <div class="chart-source">
          <i class="el-icon-document"></i>
          数据来源：问卷星调查 · n=371 · 多选题，百分比为选择该项人数占总样本比
        </div>
      </div>

      <!-- 消费意愿 -->
      <div class="chart-wrapper">
        <h3 class="chart-title">文创产品消费意愿价位分布</h3>
        <v-chart class="chart" :option="priceChartOption" autoresize />
        <div class="chart-note">
          <i class="el-icon-info"></i>
          500元以内占比超过60%，说明Z世代更倾向于轻量化、平价化的非遗产品
        </div>
        <div class="chart-source">
          <i class="el-icon-document"></i>
          数据来源：问卷星调查 · n=371 · 单选题
        </div>
      </div>
    </div>

    <!-- 数据来源说明 -->
    <div class="data-source animate__animated animate__fadeInUp animate__delay-4s">
      <i class="el-icon-document"></i>
      <p>调查说明：通过问卷星平台经微信社群/朋友圈转发，筛选条件为"1995—2009年出生"且"常住广州增城"，共回收420份，有效371份（有效率88.3%），发放时间 2025年12月—2026年1月</p>
    </div>

    <!-- 继续按钮 -->
    <div class="continue-button">
      <el-button type="primary" size="large" round @click="nextPage">
        看看现实有多残酷
        <i class="el-icon-arrow-right"></i>
      </el-button>
    </div>
  </div>
</template>

<script>
import { surveyData } from '@/data/realData'

export default {
  name: 'DataVisualizationPage',
  data() {
    return {
      surveyData,
      channelChartOption: {},
      radarChartOption: {},
      participationChartOption: {},
      priceChartOption: {}
    }
  },
  mounted() {
    this.animateNumbers()
    this.initCharts()
  },
  methods: {
    // 数字滚动动画
    animateNumbers() {
      this.animateNumber(this.$refs.heardOf, 0, this.surveyData.awareness.heardOf, 2000, '%')
      this.animateNumber(this.$refs.knowMaterial, 0, this.surveyData.awareness.knowMaterial, 2000, '%')
    },
    animateNumber(el, start, end, duration, suffix = '') {
      const range = end - start
      const increment = range / (duration / 16)
      let current = start
      
      const timer = setInterval(() => {
        current += increment
        if (current >= end) {
          current = end
          clearInterval(timer)
        }
        el.textContent = Math.floor(current) + suffix
      }, 16)
    },
    getWordStyle(value) {
      const fontSize = 14 + (value / 100) * 20
      const opacity = 0.6 + (value / 100) * 0.4
      return {
        fontSize: fontSize + 'px',
        opacity: opacity
      }
    },
    initCharts() {
      // 认知渠道柱状图
      this.channelChartOption = {
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'shadow' }
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          containLabel: true
        },
        xAxis: {
          type: 'value',
          max: 50,
          axisLabel: {
            formatter: '{value}%'
          }
        },
        yAxis: {
          type: 'category',
          data: this.surveyData.awareness.channels.map(item => item.name)
        },
        series: [{
          type: 'bar',
          data: this.surveyData.awareness.channels.map(item => item.value),
          itemStyle: {
            color: {
              type: 'linear',
              x: 0,
              y: 0,
              x2: 1,
              y2: 0,
              colorStops: [
                { offset: 0, color: '#8B4513' },
                { offset: 1, color: '#D2691E' }
              ]
            },
            borderRadius: [0, 10, 10, 0]
          },
          label: {
            show: true,
            position: 'right',
            formatter: '{c}%'
          }
        }]
      }

      // 兴趣度雷达图
      this.radarChartOption = {
        tooltip: {},
        radar: {
          indicator: this.surveyData.interest.dimensions.map(item => ({
            name: item.name,
            max: 5
          })),
          shape: 'polygon',
          splitNumber: 5,
          name: {
            textStyle: {
              color: '#333',
              fontSize: 14
            }
          },
          splitLine: {
            lineStyle: {
              color: ['#e0e0e0']
            }
          },
          splitArea: {
            areaStyle: {
              color: ['rgba(139, 69, 19, 0.05)', 'rgba(139, 69, 19, 0.1)']
            }
          }
        },
        series: [{
          type: 'radar',
          data: [{
            value: this.surveyData.interest.dimensions.map(item => item.value),
            name: 'Z世代兴趣评分',
            areaStyle: {
              color: 'rgba(139, 69, 19, 0.3)'
            },
            lineStyle: {
              color: '#8B4513',
              width: 2
            },
            itemStyle: {
              color: '#D2691E'
            }
          }]
        }]
      }

      // 参与度对比图
      this.participationChartOption = {
        tooltip: {
          trigger: 'axis',
          axisPointer: { type: 'shadow' }
        },
        legend: {
          data: ['过去一年', '未来意愿']
        },
        grid: {
          left: '3%',
          right: '4%',
          bottom: '3%',
          containLabel: true
        },
        xAxis: {
          type: 'category',
          data: ['无接触', '社媒浏览', '线下参观', '体验课程', '购买产品']
        },
        yAxis: {
          type: 'value',
          axisLabel: {
            formatter: '{value}%'
          }
        },
        series: [
          {
            name: '过去一年',
            type: 'bar',
            data: this.surveyData.participation.past.map(item => item.value),
            itemStyle: {
              color: '#909399'
            }
          },
          {
            name: '未来意愿',
            type: 'bar',
            data: this.surveyData.participation.future.map(item => item.value),
            itemStyle: {
              color: {
                type: 'linear',
                x: 0,
                y: 0,
                x2: 0,
                y2: 1,
                colorStops: [
                  { offset: 0, color: '#8B4513' },
                  { offset: 1, color: '#D2691E' }
                ]
              }
            }
          }
        ]
      }

      // 价格分布饼图
      this.priceChartOption = {
        tooltip: {
          trigger: 'item',
          formatter: '{b}: {c}% ({d}%)'
        },
        legend: {
          orient: 'vertical',
          right: '10%',
          top: 'center'
        },
        series: [{
          type: 'pie',
          radius: ['40%', '70%'],
          avoidLabelOverlap: false,
          itemStyle: {
            borderRadius: 10,
            borderColor: '#fff',
            borderWidth: 2
          },
          label: {
            show: true,
            formatter: '{b}\n{c}%'
          },
          data: this.surveyData.participation.priceRange.map((item, index) => ({
            value: item.value,
            name: item.range,
            itemStyle: {
              color: ['#8B4513', '#A0522D', '#CD853F', '#DEB887', '#F5DEB3'][index]
            }
          }))
        }]
      }
    },
    nextPage() {
      this.$router.push('/reality-gap')
    }
  }
}
</script>

<style scoped>
.data-visualization-page {
  background: #f8f9fa;
  padding-bottom: 60px;
}

.data-section {
  background: #fff;
  border-radius: 16px;
  padding: 25px;
  margin-bottom: 30px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.08);
}

.section-title {
  font-size: 22px;
  color: #333;
  margin-bottom: 25px;
  display: flex;
  align-items: center;
  gap: 10px;
  padding-bottom: 15px;
  border-bottom: 2px solid #f0f0f0;
}

.section-title i {
  color: #8B4513;
  font-size: 24px;
}

/* 统计对比 */
.stat-comparison {
  display: flex;
  justify-content: space-around;
  align-items: center;
  margin: 30px 0;
  gap: 20px;
}

.stat-item {
  flex: 1;
  text-align: center;
}

.stat-number {
  font-size: 56px;
  font-weight: bold;
  background: linear-gradient(135deg, #8B4513, #D2691E);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin-bottom: 10px;
}

.stat-label {
  font-size: 14px;
  color: #666;
  margin-bottom: 15px;
}

.stat-bar {
  height: 8px;
  background: linear-gradient(90deg, #8B4513, #D2691E);
  border-radius: 4px;
  transition: width 1.5s ease;
}

.stat-divider {
  font-size: 24px;
  font-weight: bold;
  color: #D2691E;
}

/* 图表容器 */
.chart-wrapper {
  margin: 30px 0;
}

.chart-title {
  font-size: 16px;
  color: #333;
  margin-bottom: 15px;
  font-weight: bold;
}

.chart {
  width: 100%;
  height: 300px;
}

.chart-note {
  margin-top: 15px;
  padding: 12px;
  background: #FFF8DC;
  border-left: 4px solid #8B4513;
  border-radius: 4px;
  font-size: 13px;
  color: #666;
  display: flex;
  align-items: flex-start;
  gap: 8px;
}

.chart-note i {
  color: #8B4513;
  margin-top: 2px;
}

/* 词云 */
.word-cloud-section {
  margin: 30px 0;
}

.word-cloud {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 12px;
  padding: 25px;
  background: linear-gradient(135deg, #FFF8DC, #FAEBD7);
  border-radius: 12px;
}

.word-item {
  padding: 10px 18px;
  background: rgba(139, 69, 19, 0.1);
  border-radius: 20px;
  color: #8B4513;
  font-weight: bold;
  transition: all 0.3s ease;
  cursor: pointer;
}

.word-item:hover {
  background: #8B4513;
  color: #fff;
  transform: scale(1.15);
}

/* 结论卡片 */
.conclusion-card {
  display: flex;
  justify-content: space-around;
  align-items: center;
  padding: 25px;
  background: linear-gradient(135deg, #FFF8DC, #FAEBD7);
  border-radius: 12px;
  margin: 25px 0;
  gap: 15px;
}

.conclusion-item {
  text-align: center;
  flex: 1;
}

.conclusion-item .number {
  display: block;
  font-size: 36px;
  font-weight: bold;
  color: #8B4513;
  margin-bottom: 8px;
}

.conclusion-item .text {
  display: block;
  font-size: 14px;
  color: #666;
}

.conclusion-item.highlight .number {
  color: #67C23A;
}

.conclusion-divider {
  font-size: 18px;
  font-weight: bold;
  color: #D2691E;
}

/* 洞察框 */
.insight-box {
  background: #FEF0F0;
  border: 2px solid #F56C6C;
  border-radius: 12px;
  padding: 20px;
  display: flex;
  align-items: center;
  gap: 15px;
  margin-top: 20px;
}

.insight-box i {
  font-size: 28px;
  color: #F56C6C;
}

.insight-box p {
  font-size: 15px;
  color: #333;
  margin: 0;
}

/* 图表内数据来源标注 */
.chart-source {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 10px;
  padding: 8px 12px;
  background: #f8f9fa;
  border-left: 3px solid #D2691E;
  border-radius: 0 6px 6px 0;
  font-size: 12px;
  color: #999;
}

.chart-source i {
  color: #D2691E;
  font-size: 13px;
  flex-shrink: 0;
}

/* 数据来源 */
.data-source {
  padding: 15px 20px;
  background: #FFF8DC;
  border: 1px solid #e8d5a3;
  border-radius: 8px;
  margin: 30px 0;
  display: flex;
  align-items: flex-start;
  gap: 10px;
}

.data-source i {
  color: #8B4513;
  font-size: 16px;
  flex-shrink: 0;
  margin-top: 2px;
}

.data-source p {
  font-size: 13px;
  color: #7a5c2e;
  margin: 0;
  line-height: 1.7;
}

/* 继续按钮 */
.continue-button {
  text-align: center;
  margin-top: 30px;
}

@media (max-width: 750px) {
  .stat-comparison {
    flex-direction: column;
  }
  
  .stat-divider {
    transform: rotate(90deg);
  }
  
  .conclusion-card {
    flex-direction: column;
  }
  
  .conclusion-divider {
    transform: rotate(0deg);
  }
}
</style>





















